#include<bits/stdc++.h>
using namespace std;
long long n,m,a,b,c[100010],dis1[100010],dis2[100010];
bool vis[100010];
vector<pair<long long,long long>> mp[100010];
void dijkstra(long long dis[],long long s)
{
    dis[s]=0;
    priority_queue<pair<long long,long long>> q;
    q.push({0,s});
    memset(vis,0,sizeof(vis));
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push({-dis[v],v});
            }
        }
    }
}
int main()
{
    memset(dis1,0x3f,sizeof(dis1));
    memset(dis2,0x3f,sizeof(dis2));
    scanf("%lld%lld%lld%lld",&n,&m,&a,&b);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back({v,w});
        mp[v].push_back({u,w});
    }
    dijkstra(dis1,a);
    dijkstra(dis2,b);
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        if(dis2[i]<dis1[b])
        {
            ans+=c[i];
        }
    }
    printf("%lld",ans);
    return 0;
}
